#include <stdio.h>

typedef enum {
    SUCCESS,
    ERROR_FILE_NOT_FOUND,
    ERROR_MEMORY
} result_t;

result_t process_file(const char* filename) {
    FILE* file = fopen(filename, "r");
    if (!file) {
        return ERROR_FILE_NOT_FOUND; // Compliant: proper error handling
    }
    // Process file
    fclose(file);
    return SUCCESS;
}

int main() {
    result_t result = process_file("data.txt");
    if (result != SUCCESS) {
        printf("Error processing file");
        return 1;
    }
    return 0;
}
